// ---- Pacing & tuning ------------------------------------------------------
// Calm, never-runaway field (gravity + growth both damped). All physics runs in
// WORLD-SPACE with NO boundaries — the player may fly infinitely in any
// direction. Population is managed RELATIVE TO THE CAMERA: bodies that drift far
// off-screen are culled and respawned off-screen, keeping a steady density of
// rocks around the player no matter how far they travel.
const G=0.012;                // gravity constant — gentle pull
const GRAV_EXP=1.0;           // LINEAR in mass — no exponential wells
const GRAV_SOFTEN=22000;      // large softening keeps force finite & mild
const GRAV_ACC_CAP=0.05;      // max gravity accel one body can apply per frame
const VEL_CAP=4.0;            // global speed cap for drifters (keeps field calm)
const MASS_TO_R = m=>14 + Math.pow(Math.max(0,m),0.37)*2.5; // slightly more responsive radius
const SAME_SIZE = 1.25;       // ratio under which two bodies interact as comparable peers
const PLAYER_MASS=100;
const POP=42;                 // target field population near the camera
const SAFE_R=420;             // backstop: no asteroid spawns inside this world radius of the player

// ---- CONSUME / ACCRETION GROWTH TUNING -----------------------------------
// Sub-exponential growth. Accretion (slow merge) and consume (size-mismatch) both
// route through the same absorption curve, so a slow gentle merge and a clean
// chomp grow you by comparable, controllable amounts. No instant snowball.
const ABSORB_BASE     = 0.58;  // fraction of absorbed mass kept at low speed
const DIMINISH_SCALE  = 2600;  // larger -> diminishing-returns kicks in MUCH later
const DIMINISH_FLOOR  = 0.45;  // never absorb less than this fraction of ABSORB_BASE
const CATCH_SPEED_LOSS_K   = 0.018; // efficiency lost per unit closing speed on a catch
const CATCH_SPEED_LOSS_MAX = 0.40;  // max fraction of the would-be gain lost to a violent catch

// ---- SPACE-LIKE MOTION ----------------------------------------------------
const THRUST=0.045;           // gentle acceleration — builds momentum slowly
const PLAYER_VEL_CAP=3.4;     // low cap so floating-in-space, never twitchy
const MAX_BODIES=140;         // hard ceiling on asteroids+fragments (anti-freeze)
const MAX_PARTICLES=600;      // hard ceiling on debris/exhaust particles (anti-freeze)
const MAX_DEBRIS_PER_HIT=64;  // per-collision debris cap (within MAX_PARTICLES; anti-freeze)
const MAX_FRAGS_PER_HIT=4;    // per-collision REAL-body fragment cap (anti-freeze)

// =====================================================================
// (NEW) VELOCITY-THRESHOLDED COLLISION PHYSICS
// The collision OUTCOME — not just its sparkle — is a function of the relative
// impact speed along the contact normal. Three named regimes:
//   relv <  V_MERGE          -> DEFORM + COALESCE (soft inelastic merge/accrete)
//   V_MERGE..V_FRACTURE      -> CHIP / CRACK + partially-elastic BOUNCE
//   relv >= V_FRACTURE       -> FRACTURE into multiple REAL asteroid bodies
// These thresholds are on the NORMAL component of relative velocity (the part
// that actually drives the bodies into each other) so a glancing fast pass that
// barely closes can still merge, which feels right.
// =====================================================================
const V_MERGE    = 1.15;  // below this closing speed: squash & stick (accretion)
const V_FRACTURE = 3.20;  // at/above this closing speed: shatter into real bodies
const RESTITUTION = 0.55; // bounciness for the chip/crack regime (0=stick,1=perfect)
const IMPACT_REF_SPEED = 6.0; // relv normalizer for particle/flash violence
const FRAG_MASS_LOSS = 0.18;  // fraction of parent mass lost to dust on a fracture

// ---- SOFT-BODY DEFORM / REFORM (spring) ----------------------------------
// Every body carries a deformation state: an axis (dx,dy) and a magnitude `def`
// (0 = round/rest, up to DEF_MAX = maximally squashed). On contact we inject a
// squash along the impact axis proportional to penetration & impact speed. Each
// frame the deformation RELAXES back toward 0 via a damped spring — the body
// visibly "reforms" to a rounded shape. Render squashes the polygon along the
// current axis, so deform & reform are visible on merges AND bounces.
const DEF_MAX     = 0.55;  // max squash (1 - this) along impact axis at peak
const DEF_SPRING  = 0.22;  // spring stiffness pulling deformation back to rest
const DEF_DAMP    = 0.78;  // velocity damping of the deformation spring (jelly settle)

let eaten=0, shatter=0, merged=0;
const keys={};
addEventListener('keydown',e=>{keys[e.key.toLowerCase()]=true;});
addEventListener('keyup',e=>{keys[e.key.toLowerCase()]=false;});

function rnd(a,b){return a+Math.random()*(b-a);}
// Finite guard: replace any NaN/Infinity with a fallback (anti-freeze).
function fin(v,fb){return Number.isFinite(v)?v:fb;}

// Power-law size: most asteroids are small, large ones are exponentially rarer.
function powerMass(){
  const u=Math.random();
  const t=Math.pow(u,4.2);        // heavy skew toward 0
  return 14 + t*1400;             // 14 (tiny) .. ~1400 (rare giant)
}

let idc=0;
function makeAst(m,x,y,vx,vy,player=false){
  return {id:idc++,m:fin(m,20),x:fin(x,0),y:fin(y,0),vx:fin(vx,0),vy:fin(vy,0),player,
    rot:rnd(0,6.28),vr:rnd(-.012,.012),
    verts:Array.from({length:9},()=>rnd(.78,1.18)),
    hue: player?195: rnd(20,50),
    // soft-body deformation state (rest = round):
    def:0, dvel:0, dax:1, day:0,   // current squash magnitude, its spring vel, & world axis
    flash:0};                       // crack/contact flash, fades each frame
}

// ---- Camera-relative viewport helpers (WORLD-SPACE) -----------------------
function viewRect(){
  const vw=W/cam.z, vh=H/cam.z;
  return {x0:cam.x, y0:cam.y, x1:cam.x+vw, y1:cam.y+vh, cx:cam.x+vw/2, cy:cam.y+vh/2, vw, vh};
}

// Pick a WORLD-SPACE position in the off-screen ring just beyond the viewport.
function offscreenPos(){
  const v=viewRect();
  const side=Math.floor(rnd(0,4));
  const depth=SPAWN_MARGIN+rnd(0,SPAWN_BAND);
  let x,y;
  if(side===0){ y=v.y0-depth; x=rnd(v.x0-SPAWN_BAND, v.x1+SPAWN_BAND); }
  else if(side===1){ y=v.y1+depth; x=rnd(v.x0-SPAWN_BAND, v.x1+SPAWN_BAND); }
  else if(side===2){ x=v.x0-depth; y=rnd(v.y0-SPAWN_BAND, v.y1+SPAWN_BAND); }
  else{ x=v.x1+depth; y=rnd(v.y0-SPAWN_BAND, v.y1+SPAWN_BAND); }
  return [x,y];
}

// ---- INFINITE-WORLD POPULATION MANAGEMENT ---------------------------------
const SPAWN_MARGIN=160;
const SPAWN_BAND=420;
const CULL_MARGIN=1400;

function spawnDrifter(){
  const me=asts && asts.find(a=>a.player);
  const px=me?me.x:cam.x+W/2/cam.z, py=me?me.y:cam.y+H/2/cam.z;
  const v=viewRect();
  let x=v.x0-SPAWN_MARGIN, y=v.y0-SPAWN_MARGIN;
  for(let tries=0;tries<40;tries++){
    const [tx,ty]=offscreenPos();
    if(Math.hypot(tx-px,ty-py)>=SAFE_R){ x=tx; y=ty; break; }
    x=tx; y=ty;
  }
  let dx=v.cx-x, dy=v.cy-y; const dl=Math.hypot(dx,dy)||1;
  const inSpd=rnd(0.12,0.4);
  return makeAst(powerMass(), x, y, dx/dl*inSpd+rnd(-.25,.25), dy/dl*inSpd+rnd(-.25,.25));
}

let asts=[];
let particles=[];
let shocks=[];                 // impact flash/shockwave rings
const cam={x:0,y:0,z:1};

