461	function drawAst(A){
462	  const r=MASS_TO_R(A.m);
463	  ctx.save();ctx.translate(A.x,A.y);
464	  // SOFT-BODY DEFORM: squash along the world impact axis (A.dax,A.day) by A.def.
465	  // Rotate into the axis frame, scale (1-def) along it & (1+def*0.5) across it
466	  // (volume-ish preserving), then rotate back, THEN apply the body's spin. As
467	  // A.def relaxes to 0 via the spring, the shape visibly REFORMS to round.
468	  if(A.def>0.001){
469	    const ang=Math.atan2(A.day,A.dax);
470	    ctx.rotate(ang);
471	    ctx.scale(1-A.def, 1+A.def*0.5);
472	    ctx.rotate(-ang);
473	  }
474	  ctx.rotate(A.rot);
475	  if(A.m>500){const g=ctx.createRadialGradient(0,0,r*.4,0,0,r*2.4);
476	    g.addColorStop(0,'rgba(120,90,255,.12)');g.addColorStop(1,'rgba(120,90,255,0)');
477	    ctx.fillStyle=g;ctx.beginPath();ctx.arc(0,0,r*2.4,0,6.29);ctx.fill();}
478	  ctx.beginPath();
479	  for(let k=0;k<A.verts.length;k++){const a=k/A.verts.length*6.283;const rr=r*A.verts[k];
480	    const x=Math.cos(a)*rr,y=Math.sin(a)*rr;k?ctx.lineTo(x,y):ctx.moveTo(x,y);}
481	  ctx.closePath();
482	  const l=A.player?60:32;
483	  ctx.fillStyle=`hsl(${A.hue} ${A.player?70:40}% ${l/100*40+18}%)`;
484	  ctx.fill();
