  if(me){const r=MASS_TO_R(me.m); cam.z = Math.max(0.7, Math.min(1, 120/r));
    cam.x = fin(cam.x + (me.x - W/2/cam.z - cam.x)*0.06, me.x-W/2);
    cam.y = fin(cam.y + (me.y - H/2/cam.z - cam.y)*0.06, me.y-H/2);
  }
}

// Permanently nudge a couple of silhouette vertices inward = a visible dent/crack
// that survives the reform (medium/fast hits leave a mark). Bounded, NaN-safe.
function dentVerts(A){
  if(!A.verts)return;
  const k=Math.floor(rnd(0,A.verts.length));
  A.verts[k]=Math.max(0.55, A.verts[k]-rnd(0.06,0.18));
  const k2=(k+1)%A.verts.length;
  A.verts[k2]=Math.max(0.55, A.verts[k2]-rnd(0.03,0.10));
}

function drawAst(A){
  const r=MASS_TO_R(A.m);
  ctx.save();ctx.translate(A.x,A.y);
  // SOFT-BODY DEFORM: squash along the world impact axis (A.dax,A.day) by A.def.
  // Rotate into the axis frame, scale (1-def) along it & (1+def*0.5) across it
  // (volume-ish preserving), then rotate back, THEN apply the body's spin. As
  // A.def relaxes to 0 via the spring, the shape visibly REFORMS to round.
  if(A.def>0.001){
    const ang=Math.atan2(A.day,A.dax);
    ctx.rotate(ang);
    ctx.scale(1-A.def, 1+A.def*0.5);
    ctx.rotate(-ang);
  }
  ctx.rotate(A.rot);
  if(A.m>500){const g=ctx.createRadialGradient(0,0,r*.4,0,0,r*2.4);
    g.addColorStop(0,'rgba(120,90,255,.12)');g.addColorStop(1,'rgba(120,90,255,0)');
    ctx.fillStyle=g;ctx.beginPath();ctx.arc(0,0,r*2.4,0,6.29);ctx.fill();}
  ctx.beginPath();
  for(let k=0;k<A.verts.length;k++){const a=k/A.verts.length*6.283;const rr=r*A.verts[k];
    const x=Math.cos(a)*rr,y=Math.sin(a)*rr;k?ctx.lineTo(x,y):ctx.moveTo(x,y);}
  ctx.closePath();
  const l=A.player?60:32;
  ctx.fillStyle=`hsl(${A.hue} ${A.player?70:40}% ${l/100*40+18}%)`;
  ctx.fill();
  ctx.lineWidth=2;ctx.strokeStyle=A.player?'#7fe0ff':'rgba(255,255,255,.18)';ctx.stroke();
  // contact/crack flash glow on the rim:
  if(A.flash>0.02){
    ctx.globalCompositeOperation='lighter';
    ctx.globalAlpha=Math.min(0.8,A.flash);
    ctx.lineWidth=3;ctx.strokeStyle=`hsl(${A.hue} 95% 75%)`;ctx.stroke();
    ctx.globalAlpha=1;ctx.globalCompositeOperation='source-over';
  }
  if(A.player){ctx.fillStyle='rgba(255,255,255,.85)';ctx.beginPath();ctx.arc(0,0,r*.18,0,6.29);ctx.fill();}
  ctx.restore();
}

// PARALLAX STARFIELD
const starLayers=[
  {n:90,  depth:0.20, sz:1, a:0.35},
  {n:70,  depth:0.45, sz:1.6, a:0.55},
  {n:40,  depth:0.80, sz:2.2, a:0.85},
];
function starPos(seed,axis,span){
  const s=Math.sin(seed*(axis?78.233:12.9898))*43758.5453;
  return (s-Math.floor(s))*span;
}
function drawStars(){
  const tw=W, th=H;
  for(let L=0;L<starLayers.length;L++){
    const ly=starLayers[L];
    const ox=(((cam.x*cam.z*ly.depth)%tw)+tw)%tw;
    const oy=(((cam.y*cam.z*ly.depth)%th)+th)%th;
    ctx.fillStyle='rgba(255,255,255,'+ly.a+')';
    for(let i=0;i<ly.n;i++){
      const id=i+L*1000;
      let bx=starPos(id,0,tw)-ox;
      let by=starPos(id,1,th)-oy;
      bx=((bx%tw)+tw)%tw; by=((by%th)+th)%th;
      ctx.fillRect(bx,by,ly.sz,ly.sz);
    }
  }
}

function render(){
  ctx.fillStyle='#05060a';ctx.fillRect(0,0,W,H);
  drawStars();
  ctx.save();ctx.scale(cam.z,cam.z);ctx.translate(-cam.x,-cam.y);
  for(const p of particles){ctx.globalAlpha=Math.max(0,p.life/(p.maxlife||50));ctx.fillStyle=`hsl(${p.hue} 80% 60%)`;ctx.fillRect(p.x,p.y,2.5,2.5);}
  ctx.globalAlpha=1;
  const sorted=[...asts].sort((a,b)=>a.m-b.m);
  for(const A of sorted)drawAst(A);
  ctx.globalCompositeOperation='lighter';
  for(const s of shocks){
    ctx.globalAlpha=Math.max(0,s.life)*0.55;
    ctx.lineWidth=1+3*s.life;
    ctx.strokeStyle=`hsl(${s.hue} 90% 70%)`;
    ctx.beginPath();ctx.arc(s.x,s.y,s.r,0,6.29);ctx.stroke();
  }
  ctx.globalAlpha=1;ctx.globalCompositeOperation='source-over';
  ctx.restore();

  // HUD
  const me=asts.find(a=>a.player);
  const sortedAll=[...asts].sort((a,b)=>b.m-a.m);
  document.getElementById('total').textContent=asts.length;
  document.getElementById('biggest').textContent=(sortedAll.length?sortedAll[0].m|0:'—');
  document.getElementById('eaten').textContent=eaten;
  document.getElementById('merged').textContent=merged;
  document.getElementById('shatter').textContent=shatter;
  if(me){
    document.getElementById('mass').textContent=me.m|0;
    document.getElementById('rank').textContent=sortedAll.indexOf(me)+1;
    const top=sortedAll.length?sortedAll[0].m:me.m;
    document.getElementById('growth').style.width=Math.min(100,me.m/top*100)+'%';
  } else if(!window._over){
    window._over=true;
    document.getElementById('osub').textContent='Your body was fractured/absorbed after consuming '+eaten+'.';
    document.getElementById('over').style.display='flex';
  }
}
seed();
function loop(){
  try{ step(); render(); }
  catch(err){ console.error('frame error (recovered):', err); }
  requestAnimationFrame(loop);
}
loop();
</script>
</body>
